export function formatLabel(str, ...args) {
    let replacements = [];
    if (Array.isArray(args[0])) {
        replacements = args[0];
    }
    else {
        replacements = args;
    }
    return str.replace(/{(\d+)}/g, (match, i) => {
        const replacement = replacements[i];
        return replacement !== null && replacement !== undefined
            ? replacement
            : '';
    });
}
